function fill(grid) {
  for (let row = 0; row < 9; row++) {
    for (let col = 0; col < 9; col++) {
      if (grid[row * 9 + col] == 0) {
        let allowed = getAllowed(row, col, grid);
        for (let i = 0; i < allowed.length; i++) {
          grid[row * 9 + col] = allowed[i];
          if (fill(grid)) {
            return true;
          } else {
            grid[row * 9 + col] = 0;
          }
        }
        return false;
      }
    }
  }
  return true;
}

def fill(self) -> bool:
    for row in range(9):
        for col in range(9):
            if self.is_empty(row, col):
                for digit in self.get_allowed(row, col):
                    self.grid[row, col] = digit
                    if self.fill():
                        return True
                    self.grid[row, col] = 0
                return False
    return True

fn fill(grid: &mut [u8; 81]) -> bool {
    for i in 0..81 {
        if grid[i] == 0 {
            let allowed: Vec<u8> = get_allowed(&grid, i / 9, i % 9);
            for digit in allowed {
                grid[i] = digit;
                fill(grid);
                if fill(grid) {
                    return true;
                }
                grid[i] = 0;
            }
            return false;
        }
    }
    true
}
